internal static partial class FrameScopeReportGenerator
{
    private static string ReportHtmlStyles()
    {
        return @"  <style>
    :root{--bg:#030812;--workspace:#06111f;--panel:rgba(8,24,42,.86);--panel2:rgba(12,34,58,.94);--line:rgba(60,132,190,.46);--lineHot:rgba(0,217,255,.92);--text:#f1f7ff;--muted:#afc3d9;--dim:#6f879f;--cyan:#00d9ff;--blue:#147dff;--green:#46ff6a;--yellow:#ffd84a;--purple:#9a5cff;--red:#ff4f78}
    *{box-sizing:border-box} body{margin:0;min-height:100vh;background:linear-gradient(135deg,var(--bg),#050b14 58%,#071321);color:var(--text);font-family:'Segoe UI','Microsoft YaHei UI',Arial,sans-serif;letter-spacing:0}
    .shell{width:min(1900px,calc(100vw - 28px));margin:14px auto;display:grid;grid-template-columns:316px minmax(0,1fr);gap:16px}
    .left,.main,.topbar,.card,.chart-shell{border:1px solid var(--line);background:linear-gradient(180deg,rgba(12,34,58,.91),rgba(6,18,32,.88));border-radius:18px;box-shadow:0 0 0 1px rgba(0,217,255,.06),0 18px 48px rgba(0,0,0,.34),inset 0 1px 0 rgba(255,255,255,.04)}
    .left{padding:18px}.main{padding:18px;min-width:0;background:linear-gradient(180deg,rgba(6,17,31,.98),rgba(4,12,23,.98));border-radius:22px}.brand{color:var(--text);font-size:31px;font-weight:900}.brand-sub{color:var(--cyan);font-size:14px;margin:4px 0 16px;font-weight:700}
    .block{border-top:1px solid rgba(60,132,190,.28);padding:14px 0}.block h3{margin:0 0 9px;color:var(--cyan);font-size:15px}.line{display:flex;justify-content:space-between;gap:12px;line-height:1.65;font-size:13px}.line span:first-child{color:var(--muted)}.line b{text-align:right;color:#fff1d0;overflow-wrap:anywhere}.note{color:var(--muted);font-size:13px;line-height:1.6}
    .topbar{display:flex;align-items:center;justify-content:space-between;gap:14px;padding:16px;margin-bottom:14px}.game{display:flex;align-items:center;gap:13px;min-width:0}.game-icon{width:50px;height:50px;display:grid;place-items:center;border-radius:15px;background:linear-gradient(135deg,rgba(20,125,255,.96),rgba(154,92,255,.82));border:1px solid rgba(0,217,255,.55);color:white;font-weight:900;font-size:22px;box-shadow:0 0 24px rgba(0,217,255,.23)}.game-name{font-size:24px;font-weight:900}.meta{display:flex;flex-wrap:wrap;gap:14px;color:var(--muted);font-size:13px;margin-top:4px}
    .tabs{display:flex;gap:9px;flex-wrap:wrap;justify-content:flex-end}.tab{height:38px;padding:0 14px;border-radius:13px;border:1px solid rgba(75,213,236,.42);background:rgba(13,31,51,.82);color:#d9eef7;font-weight:800;cursor:pointer;transition:transform .16s ease,border-color .16s ease,box-shadow .16s ease,background .16s ease}.tab:hover{transform:translateY(-1px);border-color:var(--lineHot);box-shadow:0 0 18px rgba(0,217,255,.16)}.tab.active{color:#031018;background:linear-gradient(135deg,var(--cyan),#48f6ff);box-shadow:0 0 22px rgba(0,217,255,.36)}.tab-disabled{border-color:rgba(120,145,168,.34);color:#8fa4b8;background:rgba(13,31,51,.52)}
    .title{display:flex;align-items:baseline;justify-content:space-between;gap:12px;margin:14px 2px 10px}.title h2{margin:0;color:var(--cyan);font-size:22px;text-shadow:0 0 16px rgba(0,217,255,.24)}.title span{color:var(--muted);font-size:13px;text-align:right}
    .gauges{display:grid;grid-template-columns:170px repeat(6,minmax(116px,1fr));gap:12px;align-items:stretch;margin:10px 0 14px}.gauge{text-align:center;min-width:0;border:1px solid rgba(60,132,190,.34);background:linear-gradient(180deg,rgba(8,24,42,.86),rgba(6,18,32,.72));border-radius:16px;padding:12px 10px;box-shadow:inset 0 0 20px rgba(0,217,255,.05)}.gauge h3{margin:0 0 9px;font-size:16px;color:#ffe8bd}.ring{--p:0;--c:var(--cyan);width:96px;height:96px;margin:auto;border-radius:50%;display:grid;place-items:center;background:radial-gradient(circle at center,#071525 0 54%,transparent 56%),conic-gradient(var(--c) calc(var(--p)*1%),rgba(85,122,145,.35) 0);box-shadow:0 0 18px color-mix(in srgb,var(--c),transparent 80%),inset 0 0 0 2px rgba(138,181,207,.25)}.ring.big{width:118px;height:118px}.ring b{font-size:25px;line-height:1;text-shadow:0 0 12px rgba(41,230,255,.36)}.ring.big b{font-size:36px;color:var(--cyan)}.ring small{display:block;color:#d8e6ef;font-size:12px;margin-top:5px}.foot{color:var(--yellow);font-size:12px;margin-top:7px;min-height:16px}
    .alert{display:none;margin:10px 0 12px;border:1px solid rgba(255,79,120,.52);background:linear-gradient(180deg,rgba(83,25,38,.78),rgba(44,14,25,.72));color:#ffe4ea;border-radius:16px;padding:12px 14px;font-size:13px;line-height:1.58;box-shadow:0 0 24px rgba(255,79,120,.12)}.alert.show{display:block}.alert b{color:#fff}
    .toolbar{display:flex;align-items:center;justify-content:space-between;gap:12px;margin:10px 0 12px;padding:12px;border:1px solid rgba(60,132,190,.32);background:rgba(8,24,42,.72);border-radius:17px;flex-wrap:wrap}.left-tools,.right-tools{display:flex;align-items:center;gap:10px;flex-wrap:wrap;min-width:0;max-width:100%}select,input,button.tool{background:rgba(12,31,51,.92);color:#fff;border:1px solid rgba(75,213,236,.45);height:38px;border-radius:13px;padding:0 12px;font-weight:800;outline:none;max-width:100%}.tool{cursor:pointer}.tool:hover{border-color:var(--lineHot);background:rgba(20,55,86,.95);box-shadow:0 0 18px rgba(0,217,255,.16)}input.search{min-width:min(260px,100%)}.range{display:flex;align-items:center;gap:8px;color:var(--muted);font-size:12px;max-width:100%}.range input{min-width:160px;padding:0}.mode-stats{min-height:30px;display:flex;align-items:center;color:#dceef7;background:rgba(12,31,51,.92);border:1px solid rgba(96,147,179,.38);border-radius:13px;padding:0 11px;font-size:12px;max-width:100%}
    .chart-shell{padding:12px}.chart-scroll{overflow-x:auto;overflow-y:hidden;border:1px solid rgba(96,147,179,.52);background:#071321;border-radius:18px;box-shadow:inset 0 0 34px rgba(0,217,255,.05)}.chartbox{position:relative;height:560px;width:100%;min-width:min(900px,100%);resize:both;overflow:hidden;cursor:crosshair;border-radius:18px;transition:border-color .2s ease,box-shadow .2s ease}.chartbox.switching{box-shadow:inset 0 0 28px rgba(41,230,255,.10)}.chartbox.dragging{cursor:grabbing;box-shadow:inset 0 0 32px rgba(41,230,255,.18)}canvas{position:absolute;inset:0;width:100%;height:100%;display:block;opacity:1;transform:translateY(0);transition:opacity .16s ease,transform .16s ease}#overlay{pointer-events:none}.chartbox.switching canvas{opacity:.46;transform:translateY(5px)}
    .tooltip{position:absolute;pointer-events:none;opacity:0;min-width:280px;max-width:470px;max-height:min(72vh,560px);overflow:auto;background:rgba(1,5,10,.97);border:1px solid rgba(0,217,255,.38);box-shadow:0 18px 46px rgba(0,0,0,.58),0 0 24px rgba(0,217,255,.12);border-radius:16px;padding:12px 14px;font-size:13px;line-height:1.58;z-index:5}.legend{display:flex;gap:10px 12px;flex-wrap:wrap;max-height:76px;overflow:auto;color:#dceef7;font-size:12px;min-width:0;max-width:100%}.legend span{min-width:0;overflow-wrap:anywhere}.legend .fps-legend-low{color:#dce6f0}.legend .fps-legend-min{color:#009dff}.legend .fps-legend-max{color:#ff3b45}.legend .fps-legend-avg{color:#31e35f}.dot{width:12px;height:12px;border-radius:99px;display:inline-block;margin-right:6px;vertical-align:-2px;box-shadow:0 0 10px currentColor}
    .panelgrid{margin-top:14px;display:grid;grid-template-columns:1fr 1fr;gap:14px}.card{padding:14px 16px;min-width:0}.card h3{margin:0 0 11px;color:var(--yellow);font-size:15px}.rows{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px 16px;font-size:13px}.row{display:grid;grid-template-columns:minmax(90px,1fr) 78px 88px;gap:8px;align-items:center;min-width:0}.row span:first-child{overflow:hidden;white-space:nowrap;text-overflow:ellipsis}.bar{height:6px;border-radius:99px;background:#19324a;overflow:hidden}.bar i{display:block;height:100%;border-radius:99px;background:linear-gradient(90deg,var(--cyan),var(--green));box-shadow:0 0 10px rgba(0,217,255,.25)}
    @media(max-width:1320px){.shell{grid-template-columns:minmax(0,1fr)}.gauges{grid-template-columns:repeat(2,minmax(0,1fr))}.panelgrid{grid-template-columns:1fr}.title{display:block}.title span{text-align:left;display:block;margin-top:5px}}
  </style>
";
    }}
